import React from "react";
import { Link } from "react-router-dom";
import "./Home.css";

const Home = ({ cartItems }) => {
  const totalItems = Object.values(cartItems).filter(q => q > 0).length;

  return (
    <div className="home-container">
      {/* Navbar */}
      <header className="navbar">
        <div className="logo">MyShop</div>
        <nav className="nav-links">
          <Link to="/">Home</Link>
          <Link to="/men">Men</Link>
          <Link to="/women">Women</Link>
          <Link to="/kids">Kids</Link>
          <Link to="/contact">Contact</Link>
        </nav>
        <div className="cart-icon">
          🛒
          {totalItems > 0 && <span className="cart-dot"></span>}
        </div>
      </header>

      {/* Main Content */}
      <main className="home-content">
        <h1>Welcome to MyShop!</h1>
        <p>Select a category to start shopping.</p>
        <div className="categories">
          <Link to="/men" className="category-card">Men</Link>
          <Link to="/women" className="category-card">Women</Link>
          <Link to="/kids" className="category-card">Kids</Link>
        </div>
      </main>
    </div>
  );
};

export default Home;
